import random

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for i in range(3):
            for j in range(0, 8, 2):
                self.board[i][j] = Piece('white')
        for i in range(5, 8):
            for j in range(0, 8, 2):
                self.board[i][j] = Piece('black')

    def print_board(self):
        for row in self.board:
            print(" ".join(str(piece) if piece else "." for piece in row))

    def move_piece(self, from_pos, to_pos):
        if not self.is_valid_move(from_pos, to_pos):
            return False

        from_row, from_col = from_pos
        to_row, to_col = to_pos
        piece = self.board[from_row][from_col]
        capture_row = (to_row + from_row) // 2
        capture_col = (to_col + from_col) // 2
        captured_piece = self.board[capture_row][capture_col]

        if captured_piece:
            del self.board[capture_row][capture_col]

        self.board[from_row][from_col] = None
        self.board[to_row][to_col] = piece

        # King the piece if it reaches the opposite end of the board
        if (piece.color == 'white' and to_row == 0) or (piece.color == 'black' and to_row == 7):
            piece.king()

        return True

    def is_valid_move(self, from_pos, to_pos):
        from_row, from_col = from_pos
        to_row, to_col = to_pos
        piece = self.board[from_row][from_col]

        if not piece:
            return False

        # Check if the move is within bounds
        if not (0 <= to_row < 8 and 0 <= to_col < 8):
            return False

        # Check if the destination is occupied
        if self.board[to_row][to_col]:
            return False

        # Check for a valid capture or non-capture move
        if abs(to_row - from_row) != (1 if piece.is_king else 2) or abs(to_col - from_col) != 2:
            return False

        # Check for valid capture direction
        if not self.board[from_row][from_col].color == 'white' and to_row < from_row:
            return False
        if not self.board[from_row][from_col].color == 'black' and to_row > from_row:
            return False

        return True

    def get_valid_moves(self, player_color):
        valid_moves = []
        for row in range(8):
            for col in range(8):
                if self.board[row][col] and self.board[row][col].color == player_color:
                    move_from = (row, col)
                    moves_to = [(row + 1, col + 2), (row + 1, col - 2), (row - 1, col + 2), (row - 1, col - 2)]
                    for to_pos in moves_to:
                        if self.is_valid_move(move_from, to_pos):
                            valid_moves.append((move_from, to_pos))
        return valid_moves

    def is_game_over(self):
        white_has_moves = any(self.get_valid_moves('white'))
        black_has_moves = any(self.get_valid_moves('black'))
        return not (white_has_moves or black_has_moves)
